#include "mlpa/analyzers/Analyzers.h"
#include <clang/AST/RecursiveASTVisitor.h>
namespace mlpa { namespace { class V: public clang::RecursiveASTVisitor<V>{public:V(clang::ASTContext&c,AnalysisResult&r):ctx(c),res(r),sm(c.getSourceManager()){} bool VisitCXXRecordDecl(clang::CXXRecordDecl*d){if(d->isThisDeclarationADefinition()&&!d->isImplicit())res.metrics.classCount++;return true;} bool VisitFunctionDecl(clang::FunctionDecl*f){if(!f->hasBody()||f->isImplicit())return true; res.metrics.functionCount++; auto b=f->getBody(); auto &m=res.metrics; auto begin=sm.getPresumedLineNumber(b->getBeginLoc()); auto end=sm.getPresumedLineNumber(b->getEndLoc()); if(end>=begin) totalLines+=end-begin+1; complexity=1; nesting=0; maxNest=0; walk(b); m.totalCyclomaticComplexity+=complexity; m.maxNestingDepth=std::max(m.maxNestingDepth,maxNest); m.averageFunctionLength=m.functionCount?static_cast<double>(totalLines)/m.functionCount:0.0; return true;} void walk(const clang::Stmt*s){if(!s)return; bool branch=llvm::isa<clang::IfStmt>(s)||llvm::isa<clang::ForStmt>(s)||llvm::isa<clang::WhileStmt>(s)||llvm::isa<clang::DoStmt>(s)||llvm::isa<clang::CaseStmt>(s)||llvm::isa<clang::ConditionalOperator>(s); if(branch){complexity++; nesting++; maxNest=std::max(maxNest,nesting);} for(auto*c:s->children())walk(c); if(branch)nesting--; }private:clang::ASTContext&ctx;AnalysisResult&res;const clang::SourceManager&sm;unsigned totalLines{0},complexity{1},nesting{0},maxNest{0};};}
void MetricsAnalyzer::analyze(clang::ASTContext &context, AnalysisResult &result){V(context,result).TraverseDecl(context.getTranslationUnitDecl());}}
